# import socket## HOST = "127.0.0.1"# # .socket(AF_INET/AF_INET6/AF_UNIX, socket.SOCK_STREAM/socket.SOCK_DGRAM)# # аргументы, по виду протокола сети(ipv4, ipv6, local) и типу сокета (TCP/UDP)# server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)# PORT = 8080## server.bind((HOST, PORT))## server.listen()# while True:#     conn, addr = server.accept()#     print(conn)#     print("connection from", addr)#     conn.send(input("Enter message: ").encode("utf-8"))##     data = conn.recv(1024)#     print(data.decode("utf-8"))import socketimport jsonimport threadingimport timedevices = []stop_event = threading.Event()def scream():    this_devise = json.dumps({"hostname": socket.gethostname(), "port": 8080})    devices.append(this_devise)    server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)    server.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)    while not stop_event.is_set():        server.sendto(this_devise.encode("utf-8"), ("192.168.0.255",8080))        # print(f"Отправлено широковещательное сообщение: {this_devise}")        time.sleep(3)    server.close()def listener():    client = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)    client.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)    client.bind(('0.0.0.0', 8080))    while True:        print(devices)        data = client.recv(100000)        if data.decode("utf-8") not in devices:            print("Найденно сообщение",data.decode("utf-8"))            devices.append(data.decode("utf-8"))            stop_event.set()def search():    t1 = threading.Thread(target=listener)    t2 = threading.Thread(target=scream)    t1.start()    t2.start()    t1.join()    t2.join()    return devicessearch()